#include <stdio.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; long long K; scanf("%d %lld", &N, &K);
        char S[100005]; scanf("%s", S);
        long long used = 0;
        int cur = 0; // cumulative increments modulo 10
        int ans = 0;
        for (int i = 0; i < N; ++i) {
            int digit = S[i] - '0';
            int curDigit = (digit + cur) % 10;
            int need = (10 - curDigit) % 10;
            if (used + need > K) break;
            used += need;
            cur = (cur + need) % 10;
            ++ans;
        }
        printf("%d\n", ans);
    }
    return 0;
}

